// TOPIC_CHANNELS 파싱: 채널별 (channelId, topic) 쌍 목록(channelId, channelName)으로 펼치기
// 형식: "채널이름/채널ID+채널이름/채널ID+..."
const raw = ($env.TOPIC_CHANNELS || '').trim();
if (!raw) {
  return [{
    json: {
      skip: true,
      reason: 'TOPIC_CHANNELS 미설정',
      parsed_valid_channels: 0,
      parsed_invalid_channels: 0,
    },
  }];
}

const valid = [];
const invalid = [];

for (const chunk of raw.split('+')) {
  const part = (chunk || '').trim();
  if (!part) continue;

  const slashIdx = part.indexOf('/');
  if (slashIdx < 0) {
    invalid.push({ raw: part, reason: '채널명/채널ID 구분자(/) 없음' });
    continue;
  }

  const channelName = part.slice(0, slashIdx).trim();
  const channelId = part.slice(slashIdx + 1).trim();

  if (!channelName || !channelId) {
    invalid.push({ raw: part, reason: '채널명 또는 채널ID 비어 있음' });
    continue;
  }

  valid.push({ channelId, channelName });
}

const summary = {
  parsed_valid_channels: valid.length,
  parsed_invalid_channels: invalid.length,
};

console.log(`[WF-09] TOPIC_CHANNELS parsed: valid=${summary.parsed_valid_channels}, invalid=${summary.parsed_invalid_channels}`);
if (valid.length > 0) {
  console.log(`[WF-09] TOPIC_CHANNELS valid channelNames: ${valid.map(v => v.channelName).join(', ')}`);
}
if (invalid.length > 0) {
  const preview = invalid.slice(0, 10).map((x) => `${x.raw}(${x.reason})`).join(', ');
  console.log(`[WF-09] TOPIC_CHANNELS invalid entries: ${preview}`);
}

const validItems = valid.map((ch) => ({
  json: {
    ...ch,
    ...summary,
  },
}));

const invalidItems = invalid.map((err) => ({
  json: {
    skip: true,
    reason: `TOPIC_CHANNELS 항목 형식 오류: ${err.raw} (${err.reason})`,
    raw_entry: err.raw,
    ...summary,
  },
}));

if (validItems.length === 0) {
  if (invalidItems.length > 0) return invalidItems;
  return [{ json: { skip: true, reason: '파싱된 채널 없음', ...summary } }];
}

// 유효 채널은 다음 단계로, 무효 채널은 skip=true 아이템으로 함께 반환 (가시성 확보)
return [...validItems, ...invalidItems];

// YouTube RSS 조회 + 짧은 실행시간 내 재시도 + 새 영상 필터링(Shorts 제외)
const channelId = ($json.channelId || '').trim();
const channelName = ($json.channelName || '').trim();

if (!channelId) {
  return { json: { skip: true, channelId, channelName, reason: 'channelId 없음' } };
}

const RSS_URL = `https://www.youtube.com/feeds/videos.xml?channel_id=${channelId}`;

// B전략: 한 번 실행은 짧게 끝내고, 다음 스케줄에서 재시도
const MAX_ATTEMPTS = 8;                    // 최대 8회 요청
const ATTEMPT_TIMEOUT_MS = 6000;           // 개별 요청 타임아웃 6초
const MAX_TOTAL_WAIT_MS = 60 * 1000;       // 코드노드 총 실행시간 60초 상한
const WAIT_STEPS_MS = [1500, 2000, 2500, 3000, 3500, 4500, 6000];

const CUTOFF_MS = Date.now() - 90 * 60 * 1000; // 1.5시간

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
const decodeEntities = (text = '') =>
  text
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'");

const asArray = (v) => (Array.isArray(v) ? v : (v == null ? [] : [v]));
const textOf = (v) => {
  if (typeof v === 'string') return v;
  if (Array.isArray(v)) return textOf(v[0]);
  if (!v || typeof v !== 'object') return '';
  if (typeof v._ === 'string') return v._;
  if (typeof v['#text'] === 'string') return v['#text'];
  return '';
};

const extractHref = (linkVal) => {
  for (const link of asArray(linkVal)) {
    if (!link) continue;
    if (typeof link === 'string') return link;
    if (typeof link.href === 'string') return link.href;
    if (link.$ && typeof link.$.href === 'string') return link.$.href;
    if (link.attrs && typeof link.attrs.href === 'string') return link.attrs.href;
  }
  return '';
};

const normalizeVideoUrl = (videoId, link) => {
  if (typeof link === 'string' && link.includes('youtube.com/watch')) return link;
  if (videoId) return `https://www.youtube.com/watch?v=${videoId}`;
  return '';
};

const parseFromXml = (xml) => {
  const out = [];
  const entryRegex = /<entry>([\s\S]*?)<\/entry>/g;
  let match;
  while ((match = entryRegex.exec(xml)) !== null) {
    const block = match[1];
    const videoId = (block.match(/<yt:videoId>([^<]+)<\/yt:videoId>/) || [])[1] || '';
    const title = (block.match(/<title>([^<]+)<\/title>/) || [])[1] || '';
    const publishedAt = (block.match(/<published>([^<]+)<\/published>/) || [])[1] || '';
    const linkMatch = block.match(/<link rel="alternate" href="([^"]+)"/);
    const link = linkMatch ? linkMatch[1] : '';
    if (!videoId) continue;
    out.push({
      videoId,
      title: decodeEntities(title),
      publishedAt,
      videoUrl: normalizeVideoUrl(videoId, link),
    });
  }
  return out;
};

const parseFromObject = (data) => {
  const feed = data && data.feed ? data.feed : data;
  const rawEntries = feed && feed.entry ? asArray(feed.entry) : [];
  const out = [];

  for (const raw of rawEntries) {
    if (!raw || typeof raw !== 'object') continue;
    const videoId = textOf(raw['yt:videoId']) || textOf(raw.videoId);
    if (!videoId) continue;

    const title = decodeEntities(textOf(raw.title));
    const publishedAt = textOf(raw.published) || textOf(raw.updated);
    const link = extractHref(raw.link);

    out.push({
      videoId,
      title,
      publishedAt,
      videoUrl: normalizeVideoUrl(videoId, link),
    });
  }

  return out;
};

let parsedEntries = [];
let fetchMode = '';
let lastError = '';
let attemptsUsed = 0;
const startMs = Date.now();

for (let attempt = 1; attempt <= MAX_ATTEMPTS; attempt++) {
  attemptsUsed = attempt;
  const elapsed = Date.now() - startMs;
  if (elapsed >= MAX_TOTAL_WAIT_MS) {
    lastError = `실행시간 상한 ${Math.floor(MAX_TOTAL_WAIT_MS / 1000)}초 도달`;
    break;
  }

  try {
    const response = await $helpers.httpRequest({
      method: 'GET',
      url: RSS_URL,
      options: { timeout: ATTEMPT_TIMEOUT_MS },
    });

    if (typeof response === 'string') {
      if (response.includes('<feed')) {
        parsedEntries = parseFromXml(response);
        fetchMode = 'xml-string';
        console.log(`[WF-09] RSS 성공(channel=${channelId}, attempt=${attempt}, mode=${fetchMode}, entries=${parsedEntries.length})`);
        break;
      }
      lastError = `문자열 응답이나 feed 태그 없음(len=${response.length})`;
    } else if (response && typeof response === 'object') {
      const candidate = (response.body && (typeof response.body === 'string' || typeof response.body === 'object'))
        ? response.body
        : response;

      if (typeof candidate === 'string' && candidate.includes('<feed')) {
        parsedEntries = parseFromXml(candidate);
        fetchMode = 'xml-string-in-body';
        console.log(`[WF-09] RSS 성공(channel=${channelId}, attempt=${attempt}, mode=${fetchMode}, entries=${parsedEntries.length})`);
        break;
      }

      if (candidate && typeof candidate === 'object' && (candidate.feed || candidate.entry)) {
        parsedEntries = parseFromObject(candidate);
        fetchMode = 'parsed-object';
        console.log(`[WF-09] RSS 성공(channel=${channelId}, attempt=${attempt}, mode=${fetchMode}, entries=${parsedEntries.length})`);
        break;
      }

      lastError = `객체 응답이나 feed/entry 구조 없음`;
    } else {
      lastError = `지원되지 않는 응답 타입(${typeof response})`;
    }
  } catch (e) {
    lastError = e && e.message ? e.message : String(e);
    console.log(`[WF-09] attempt ${attempt} RSS 오류(channel=${channelId}) - ${lastError}`);
  }

  if (attempt < MAX_ATTEMPTS) {
    const elapsedAfter = Date.now() - startMs;
    if (elapsedAfter >= MAX_TOTAL_WAIT_MS) {
      lastError = `실행시간 상한 ${Math.floor(MAX_TOTAL_WAIT_MS / 1000)}초 도달`;
      break;
    }
    const waitMs = WAIT_STEPS_MS[Math.min(attempt - 1, WAIT_STEPS_MS.length - 1)];
    const remaining = MAX_TOTAL_WAIT_MS - elapsedAfter;
    if (remaining <= 0) {
      lastError = `실행시간 상한 ${Math.floor(MAX_TOTAL_WAIT_MS / 1000)}초 도달`;
      break;
    }
    await sleep(Math.min(waitMs, remaining));
  }
}

if (!fetchMode) {
  return {
    json: {
      skip: true,
      channelId,
      channelName,
      reason: `RSS 재시도 종료(${lastError || 'unknown'})`,
      attemptsUsed,
      executionWindowMs: MAX_TOTAL_WAIT_MS,
      retryStrategy: 'short-window-next-schedule',
    },
  };
}

if (parsedEntries.length === 0) {
  return {
    json: {
      skip: true,
      channelId,
      channelName,
      reason: `피드 응답은 성공했지만 entry 없음(mode=${fetchMode})`,
      attemptsUsed,
      retryStrategy: 'short-window-next-schedule',
    },
  };
}

const freshEntries = [];
for (const entry of parsedEntries) {
  const videoUrl = entry.videoUrl || (entry.videoId ? `https://www.youtube.com/watch?v=${entry.videoId}` : '');
  if (!videoUrl) continue;

  if (videoUrl.includes('/shorts/')) continue;

  const publishedMs = Date.parse(entry.publishedAt || '');
  if (!Number.isFinite(publishedMs)) continue;

  if (publishedMs >= CUTOFF_MS) {
    freshEntries.push({
      videoUrl,
      title: entry.title || '',
      publishedAt: entry.publishedAt || '',
      channelId,
      channelName,
      fetchMode,
      attemptsUsed,
    });
  }
}

if (freshEntries.length === 0) {
  return {
    json: {
      skip: true,
      channelId,
      channelName,
      reason: `새 영상 없음(1.5시간 이내, mode=${fetchMode}, entries=${parsedEntries.length})`,
      attemptsUsed,
    },
  };
}

return freshEntries.map((e) => ({ json: e })); // n8n will emit one item per entry

// 결과 로깅
const result = $input.item.json;

if (result.duplicate) {
  console.log(`[WF-09] 중복 건너뜀`);
} else if (result.added) {
  console.log(`[WF-09] 소스 추가 완료 (cleaned=${result.cleaned_up})`);
} else if (result.error) {
  console.error(`[WF-09] 소스 추가 실패: ${result.error}`);
}

return { json: result };
